1	package com.booking.filter;
2	
3	import com.booking.domain.BlacklistEntry;
4	import com.booking.domain.User;
5	import com.booking.mapper.BlacklistMapper;
6	import jakarta.servlet.Filter;
7	import jakarta.servlet.FilterChain;
8	import jakarta.servlet.ServletException;
9	import jakarta.servlet.ServletRequest;
10	import jakarta.servlet.ServletResponse;
11	import jakarta.servlet.http.HttpServletRequest;
12	import jakarta.servlet.http.HttpServletResponse;
13	import jakarta.servlet.http.HttpSession;
14	import org.springframework.stereotype.Component;
15	
16	import java.io.IOException;
17	
18	@Component
19	public class AuthFilter implements Filter {
20	
21	    private final BlacklistMapper blacklistMapper;
22	
23	    public AuthFilter(BlacklistMapper blacklistMapper) {
24	        this.blacklistMapper = blacklistMapper;
25	    }
26	
27	    @Override
28	    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
29	            throws IOException, ServletException {
30	
31	        HttpServletRequest httpReq = (HttpServletRequest) request;
32	        HttpServletResponse httpResp = (HttpServletResponse) response;
33	
34	        String path = httpReq.getRequestURI();
35	
36	        // Allow auth endpoints without session
37	        if (path.startsWith("/api/auth/")) {
38	            chain.doFilter(request, response);
39	            return;
40	        }
41	
42	        HttpSession session = httpReq.getSession(false);
43	        if (session == null || session.getAttribute("currentUser") == null) {
44	            httpResp.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
45	            httpResp.setContentType("application/json");
46	            httpResp.getWriter().write("{\"error\":\"Authentication required\"}");
47	            return;
48	        }
49	
50	        // Check blacklist status
51	        User user = (User) session.getAttribute("currentUser");
52	        BlacklistEntry bl = blacklistMapper.findActiveByUserId(user.getId());
53	        if (bl != null && !bl.isExpired()) {
54	            httpResp.setStatus(HttpServletResponse.SC_FORBIDDEN);
55	            httpResp.setContentType("application/json");
56	            httpResp.getWriter().write("{\"error\":\"Account is blacklisted: " +
57	                    bl.getReason().replace("\"", "'") + "\"}");
58	            return;
59	        }
60	
61	        chain.doFilter(request, response);
62	    }
63	}
