1	package com.booking.config;
2	
3	import com.booking.domain.User;
4	import com.booking.mapper.UserMapper;
5	import com.booking.util.FieldEncryptor;
6	import org.slf4j.Logger;
7	import org.slf4j.LoggerFactory;
8	import org.springframework.boot.CommandLineRunner;
9	import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
10	import org.springframework.stereotype.Component;
11	
12	import java.util.List;
13	
14	@Component
15	public class DataInitializer implements CommandLineRunner {
16	
17	    private static final Logger log = LoggerFactory.getLogger(DataInitializer.class);
18	    private static final String PLACEHOLDER = "$PLACEHOLDER$";
19	    private static final String DEFAULT_PASSWORD = "password123";
20	
21	    private final UserMapper userMapper;
22	    private final BCryptPasswordEncoder passwordEncoder;
23	
24	    public DataInitializer(UserMapper userMapper, BCryptPasswordEncoder passwordEncoder) {
25	        this.userMapper = userMapper;
26	        this.passwordEncoder = passwordEncoder;
27	    }
28	
29	    @Override
30	    public void run(String... args) {
31	        List<User> users = userMapper.findAll();
32	        int pwdUpdated = 0;
33	        int phoneEncrypted = 0;
34	        for (User user : users) {
35	            if (PLACEHOLDER.equals(user.getPasswordHash())) {
36	                userMapper.updatePasswordHash(user.getId(), passwordEncoder.encode(DEFAULT_PASSWORD));
37	                pwdUpdated++;
38	            }
39	            // Encrypt plaintext phone numbers at rest
40	            String phone = user.getPhone();
41	            if (phone != null && !phone.isEmpty() && !isEncrypted(phone)) {
42	                userMapper.updatePhone(user.getId(), FieldEncryptor.encrypt(phone));
43	                phoneEncrypted++;
44	            }
45	        }
46	        if (pwdUpdated > 0) log.info("Initialized passwords for {} seed users", pwdUpdated);
47	        if (phoneEncrypted > 0) log.info("Encrypted phone numbers for {} users", phoneEncrypted);
48	    }
49	
50	    private boolean isEncrypted(String value) {
51	        // Encrypted values are Base64-encoded and significantly longer than plain phone numbers
52	        try {
53	            FieldEncryptor.decrypt(value);
54	            return true;
55	        } catch (Exception e) {
56	            return false;
57	        }
58	    }
59	}
