1	package com.booking.domain;
2	
3	import java.util.Map;
4	import java.util.Set;
5	
6	public enum OrderStatus {
7	    CREATED,
8	    CONFIRMED,
9	    PAID,
10	    CHECKED_IN,
11	    CHECKED_OUT,
12	    COMPLETED,
13	    CANCELLED,
14	    REFUNDED;
15	
16	    private static final Map<OrderStatus, Set<OrderStatus>> TRANSITIONS = Map.of(
17	            CREATED,     Set.of(CONFIRMED, CANCELLED),
18	            CONFIRMED,   Set.of(PAID, CANCELLED),
19	            PAID,        Set.of(CHECKED_IN, CANCELLED, REFUNDED),
20	            CHECKED_IN,  Set.of(CHECKED_OUT, CANCELLED),
21	            CHECKED_OUT, Set.of(COMPLETED),
22	            COMPLETED,   Set.of(REFUNDED),
23	            CANCELLED,   Set.of(),
24	            REFUNDED,    Set.of()
25	    );
26	
27	    public boolean canTransitionTo(OrderStatus target) {
28	        Set<OrderStatus> allowed = TRANSITIONS.get(this);
29	        return allowed != null && allowed.contains(target);
30	    }
31	
32	    public boolean isTerminal() {
33	        return this == CANCELLED || this == REFUNDED || this == COMPLETED;
34	    }
35	
36	    public boolean isRefundable() {
37	        return this == PAID || this == CHECKED_IN || this == COMPLETED;
38	    }
39	
40	    public boolean canReschedule() {
41	        return this == CREATED || this == CONFIRMED || this == PAID;
42	    }
43	}
