39	    @GetMapping("/{id}")
40	    public ResponseEntity<?> get(@PathVariable Long id, HttpSession session) {
41	        User user = SessionUtil.getCurrentUser(session);
42	        Order order = orderService.getById(id);
43	        if (order == null) return ResponseEntity.notFound().build();
44	        if (!orderService.canUserAccess(order, user))
45	            return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
46	        return ResponseEntity.ok(order);
