55	            return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
56	        return ResponseEntity.ok(orderService.getAuditTrail(id));
57	    }
58	
59	    @PostMapping
60	    public ResponseEntity<?> create(@RequestBody Map<String, Object> body,
61	                                    @RequestHeader(value = "Idempotency-Key") String idempotencyKey,
62	                                    HttpSession session) {
63	        String action = "CREATE_ORDER";
64	        IdempotencyResult idem = idempotencyService.checkToken(idempotencyKey, action, null);
65	        if (idem.isDuplicate) {
66	            return ResponseEntity.status(idem.cachedStatus).body(idem.cachedBody);
67	        }
68	
69	        User user = SessionUtil.getCurrentUser(session);
70	        try {
71	            Long listingId = ((Number) body.get("listingId")).longValue();
72	            Long timeSlotId = ((Number) body.get("timeSlotId")).longValue();
73	            Long addressId = body.get("addressId") != null ? ((Number) body.get("addressId")).longValue() : null;
74	            String notes = (String) body.get("notes");
75	            String deliveryMode = (String) body.get("deliveryMode");
76	
77	            Order order = orderService.createOrder(listingId, timeSlotId, addressId, notes, deliveryMode, user);
78	
79	            String responseBody = objectMapper.writeValueAsString(order);
80	            // For CREATE, orderId was null at check time — use null for consistent scoped key
81	            idempotencyService.recordResponse(idempotencyKey, action, null, 200, responseBody);
82	            return ResponseEntity.ok(order);
83	        } catch (IllegalArgumentException | IllegalStateException e) {
84	            idempotencyService.recordResponse(idempotencyKey, action, null, 400, e.getMessage());
85	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
86	        } catch (SecurityException e) {
87	            idempotencyService.recordResponse(idempotencyKey, action, null, 403, e.getMessage());
88	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
89	        } catch (Exception e) {
90	            idempotencyService.recordResponse(idempotencyKey, action, null, 500, e.getMessage());
91	            return ResponseEntity.internalServerError().body(Map.of("error", "Order creation failed"));
92	        }
93	    }
94	
