46	        if (existing != null) {
47	            if (existing.isExpired()) {
48	                return new IdempotencyResult(false, null, null);
49	            }
50	            if (existing.getResponseStatus() != null) {
51	                return new IdempotencyResult(true, existing.getResponseStatus(), existing.getResponseBody());
