42	    public ResponseEntity<?> register(@RequestBody Map<String, String> data, HttpSession session) {
43	        // Strict DTO validation
44	        String username = data.get("username");
45	        String email = data.get("email");
46	        String password = data.get("password");
47	        String fullName = data.get("fullName");
48	
49	        if (username == null || username.isBlank()) {
50	            return ResponseEntity.badRequest().body(Map.of("error", "Username is required"));
51	        }
52	        if (email == null || !email.matches("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$")) {
53	            return ResponseEntity.badRequest().body(Map.of("error", "Valid email is required"));
54	        }
55	        if (password == null || password.length() < 6) {
56	            return ResponseEntity.badRequest().body(Map.of("error", "Password must be at least 6 characters"));
57	        }
58	        if (fullName == null || fullName.isBlank()) {
59	            return ResponseEntity.badRequest().body(Map.of("error", "Full name is required"));
60	        }
61	
62	        try {
63	            User user = authService.register(username, email, password, fullName,
64	                    data.get("phone"), 1L);
65	            SessionUtil.setCurrentUser(session, user);
66	            return ResponseEntity.ok(Map.of("message", "Registration successful", "userId", user.getId()));
67	        } catch (IllegalArgumentException e) {
68	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
69	        }
70	    }
