24	
25	    private final NotificationMapper notificationMapper;
26	    private final NotificationPreferenceMapper prefMapper;
27	    private final UserMapper userMapper;
28	    private final NotificationDispatcher dispatcher;
29	
30	    public NotificationService(NotificationMapper notificationMapper,
