62	    public void retryNotification(Long notificationId) {
63	        NotificationRecord r = notificationMapper.findById(notificationId);
64	        if (r == null) return;
65	        if (r.getRetryCount() != null && r.getRetryCount() >= MAX_RETRIES) {
66	            notificationMapper.markTerminal(notificationId);
67	            return;
68	        }
69	        notificationMapper.incrementRetry(notificationId);
70	        notificationMapper.updateStatus(notificationId, "QUEUED");
71	    }
72	
73	    /**
74	     * True queue lifecycle: attempt dispatch, increment failure on error, mark terminal after max retries.
75	     */
76	    public void processRetryQueue() {
77	        List<NotificationRecord> queued = notificationMapper.findQueued();
78	        for (NotificationRecord r : queued) {
79	            boolean dispatched = attemptDispatch(r);
80	            if (dispatched) {
81	                notificationMapper.updateStatus(r.getId(), "READY_FOR_EXPORT");
82	            } else {
83	                notificationMapper.incrementRetry(r.getId());
84	                int newCount = (r.getRetryCount() != null ? r.getRetryCount() : 0) + 1;
85	                if (newCount >= MAX_RETRIES) {
86	                    notificationMapper.markTerminal(r.getId());
87	                    log.warn("Notification {} marked terminal after {} failures", r.getId(), newCount);
88	                } else {
89	                    notificationMapper.updateStatus(r.getId(), "RETRY");
90	                    log.info("Notification {} failed, retry {}/{}", r.getId(), newCount, MAX_RETRIES);
91	                }
92	            }
93	        }
94	    }
95	
96	    private boolean attemptDispatch(NotificationRecord record) {
97	        return dispatcher.dispatch(record);
98	    }
