14	
15	@Service
16	public class BlacklistService {
17	
18	    private static final Logger log = LoggerFactory.getLogger(BlacklistService.class);
19	    private static final int DEFAULT_DURATION_DAYS = 7;
20	
21	    private final BlacklistMapper blacklistMapper;
22	    private final UserMapper userMapper;
23	
24	    public BlacklistService(BlacklistMapper blacklistMapper, UserMapper userMapper) {
25	        this.blacklistMapper = blacklistMapper;
26	        this.userMapper = userMapper;
27	    }
28	
29	    public List<BlacklistEntry> getAll() {
30	        return blacklistMapper.findAll();
31	    }
32	
33	    public BlacklistEntry getById(Long id) {
34	        return blacklistMapper.findById(id);
35	    }
36	
37	    public BlacklistEntry getActiveByUser(Long userId) {
38	        return blacklistMapper.findActiveByUserId(userId);
39	    }
40	
41	    public boolean isBlacklisted(Long userId) {
42	        BlacklistEntry entry = blacklistMapper.findActiveByUserId(userId);
43	        return entry != null && !entry.isExpired();
44	    }
45	
46	    @Transactional
47	    public BlacklistEntry blacklist(Long userId, String reason, Integer durationDays, User admin) {
48	        if (!"ADMINISTRATOR".equals(admin.getRoleName())) {
49	            throw new SecurityException("Only administrators can blacklist accounts");
50	        }
51	        if (reason == null || reason.isBlank()) {
52	            throw new IllegalArgumentException("Blacklist reason is required and must not be empty");
53	        }
54	
55	        User target = userMapper.findById(userId);
56	        if (target == null) throw new IllegalArgumentException("User not found");
57	        if ("ADMINISTRATOR".equals(target.getRoleName())) {
58	            throw new IllegalArgumentException("Cannot blacklist an administrator");
59	        }
60	
61	        // Deactivate any existing active blacklist for this user
62	        BlacklistEntry existing = blacklistMapper.findActiveByUserId(userId);
63	        if (existing != null) {
64	            blacklistMapper.deactivate(existing.getId(), admin.getId(), "Replaced by new blacklist entry");
65	        }
66	
67	        int days = (durationDays != null && durationDays > 0) ? durationDays : DEFAULT_DURATION_DAYS;
68	        LocalDateTime now = LocalDateTime.now();
69	
70	        BlacklistEntry entry = new BlacklistEntry();
71	        entry.setUserId(userId);
72	        entry.setReason(reason);
73	        entry.setBlacklistedBy(admin.getId());
74	        entry.setDurationDays(days);
75	        entry.setStartsAt(now);
76	        entry.setExpiresAt(now.plusDays(days));
77	        entry.setActive(true);
78	        blacklistMapper.insert(entry);
79	
80	        // Disable the user account
81	        userMapper.updateEnabled(userId, false);
82	
83	        log.info("User {} blacklisted by admin {} for {} days: {}", userId, admin.getId(), days, reason);
84	        return blacklistMapper.findById(entry.getId());
85	    }
86	
87	    @Transactional
88	    public BlacklistEntry lift(Long blacklistId, String liftReason, User admin) {
89	        if (!"ADMINISTRATOR".equals(admin.getRoleName())) {
90	            throw new SecurityException("Only administrators can lift blacklists");
91	        }
92	
93	        BlacklistEntry entry = blacklistMapper.findById(blacklistId);
94	        if (entry == null) throw new IllegalArgumentException("Blacklist entry not found");
95	        if (!entry.getActive()) throw new IllegalStateException("Blacklist entry is already inactive");
96	
97	        blacklistMapper.deactivate(blacklistId, admin.getId(), liftReason);
98	
99	        // Re-enable the user
100	        userMapper.updateEnabled(entry.getUserId(), true);

