1	package com.booking.util;
2	
3	import javax.crypto.Cipher;
4	import javax.crypto.spec.GCMParameterSpec;
5	import javax.crypto.spec.SecretKeySpec;
6	import java.nio.charset.StandardCharsets;
7	import java.security.SecureRandom;
8	import java.util.Base64;
9	
10	public final class FieldEncryptor {
11	
12	    private static final String ALGORITHM = "AES/GCM/NoPadding";
13	    private static final int GCM_TAG_LENGTH = 128;
14	    private static final int IV_LENGTH = 12;
15	    private static final SecureRandom RANDOM = new SecureRandom();
16	
17	    private static volatile SecretKeySpec keySpec;
18	
19	    private FieldEncryptor() {}
20	
21	    public static void configure(String key) {
22	        if (key == null || key.length() < 16) {
23	            throw new IllegalArgumentException("Encryption key must be at least 16 characters");
24	        }
25	        byte[] raw = key.getBytes(StandardCharsets.UTF_8);
26	        byte[] sized = new byte[16];
27	        System.arraycopy(raw, 0, sized, 0, Math.min(raw.length, 16));
28	        keySpec = new SecretKeySpec(sized, "AES");
29	    }
30	
31	    private static SecretKeySpec getKeySpec() {
32	        if (keySpec == null) {
33	            throw new IllegalStateException(
34	                "Encryption key not configured. Set ENCRYPTION_KEY environment variable or app.encryption-key property.");
35	        }
36	        return keySpec;
37	    }
38	
39	    public static boolean isConfigured() {
40	        return keySpec != null;
41	    }
42	
43	    public static String encrypt(String plaintext) {
44	        if (plaintext == null) return null;
45	        try {
46	            byte[] iv = new byte[IV_LENGTH];
47	            RANDOM.nextBytes(iv);
48	            Cipher cipher = Cipher.getInstance(ALGORITHM);
49	            cipher.init(Cipher.ENCRYPT_MODE, getKeySpec(), new GCMParameterSpec(GCM_TAG_LENGTH, iv));
50	            byte[] encrypted = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
51	            byte[] combined = new byte[IV_LENGTH + encrypted.length];
52	            System.arraycopy(iv, 0, combined, 0, IV_LENGTH);
53	            System.arraycopy(encrypted, 0, combined, IV_LENGTH, encrypted.length);
54	            return Base64.getEncoder().encodeToString(combined);
55	        } catch (Exception e) {
56	            throw new RuntimeException("Encryption failed", e);
57	        }
58	    }
59	
60	    public static String decrypt(String ciphertext) {
61	        if (ciphertext == null) return null;
62	        try {
63	            byte[] combined = Base64.getDecoder().decode(ciphertext);
64	            byte[] iv = new byte[IV_LENGTH];
65	            System.arraycopy(combined, 0, iv, 0, IV_LENGTH);
66	            byte[] encrypted = new byte[combined.length - IV_LENGTH];
67	            System.arraycopy(combined, IV_LENGTH, encrypted, 0, encrypted.length);
68	            Cipher cipher = Cipher.getInstance(ALGORITHM);
69	            cipher.init(Cipher.DECRYPT_MODE, getKeySpec(), new GCMParameterSpec(GCM_TAG_LENGTH, iv));
70	            return new String(cipher.doFinal(encrypted), StandardCharsets.UTF_8);
71	        } catch (Exception e) {
72	            throw new RuntimeException("Decryption failed", e);
73	        }
74	    }
75	}
