132	    }
133	
134	    @PostMapping("/{id}/cancel")
135	    public ResponseEntity<?> cancel(@PathVariable Long id, @RequestBody Map<String, String> body,
136	                                    @RequestHeader(value = "Idempotency-Key") String key,
137	                                    HttpSession session) {
