155	                                        @RequestHeader(value = "Idempotency-Key") String key,
156	                                        HttpSession session) {
157	        return executeAction(key, "RESCHEDULE", id, session, (order, user) -> {
158	            Long newSlotId = ((Number) body.get("newTimeSlotId")).longValue();
159	            return orderService.reschedule(id, newSlotId, user);
160	        });
161	    }
