2	
3	import com.booking.domain.Address;
4	import com.booking.domain.User;
5	import com.booking.mapper.AddressMapper;
6	import org.springframework.stereotype.Service;
7	import org.springframework.transaction.annotation.Transactional;
8	
9	import java.util.List;
10	import java.util.Map;
11	import java.util.Set;
12	import java.util.regex.Pattern;
13	
14	@Service
15	public class AddressService {
16	
17	    private static final Pattern ZIP_PATTERN = Pattern.compile("^\\d{5}(-\\d{4})?$");
18	    private static final Set<String> US_STATES = Set.of(
19	            "AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA",
20	            "KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ",
21	            "NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT",
22	            "VA","WA","WV","WI","WY","DC");
23	
24	    private final AddressMapper addressMapper;
25	
26	    public AddressService(AddressMapper addressMapper) {
27	        this.addressMapper = addressMapper;
28	    }
29	
30	    public List<Address> getByUser(Long userId) {
31	        return addressMapper.findByUserId(userId);
32	    }
33	
34	    public Address getById(Long id) {
35	        return addressMapper.findById(id);
36	    }
37	
38	    @Transactional
39	    public Address create(Address address, User actor) {
40	        address.setUserId(actor.getId());
41	        if (address.getCountry() == null) address.setCountry("US");
42	        validateAddress(address);
43	        if (Boolean.TRUE.equals(address.getIsDefault())) {
44	            addressMapper.clearDefault(actor.getId());
45	        }
46	        addressMapper.insert(address);
47	        return addressMapper.findById(address.getId());
48	    }
49	
50	    @Transactional
51	    public Address update(Address address, User actor) {
52	        Address existing = addressMapper.findById(address.getId());
53	        if (existing == null) throw new IllegalArgumentException("Address not found");
54	        if (!existing.getUserId().equals(actor.getId()) && !"ADMINISTRATOR".equals(actor.getRoleName())) {
55	            throw new SecurityException("Access denied");
56	        }
57	        address.setUserId(existing.getUserId());
58	        validateAddress(address);
59	        if (Boolean.TRUE.equals(address.getIsDefault())) {
60	            addressMapper.clearDefault(existing.getUserId());
61	        }
62	        addressMapper.update(address);
63	        return addressMapper.findById(address.getId());
64	    }
65	
66	    public void delete(Long id, User actor) {
67	        Address existing = addressMapper.findById(id);
68	        if (existing == null) throw new IllegalArgumentException("Address not found");
69	        if (!existing.getUserId().equals(actor.getId()) && !"ADMINISTRATOR".equals(actor.getRoleName())) {
70	            throw new SecurityException("Access denied");
71	        }
72	        addressMapper.delete(id);
73	    }
74	
75	    // ZIP prefix -> state region mapping for consistency checks
76	    private static final Map<Character, Set<String>> ZIP_STATE_REGIONS = Map.of(
77	        '0', Set.of("CT","MA","ME","NH","NJ","NY","PR","RI","VT","VI","DC"),
78	        '1', Set.of("DE","NY","PA"),
79	        '2', Set.of("DC","MD","NC","SC","VA","WV"),
80	        '3', Set.of("AL","FL","GA","MS","TN"),
81	        '4', Set.of("IN","KY","MI","OH"),
82	        '5', Set.of("IA","MN","MT","ND","NE","SD","WI"),
83	        '6', Set.of("IL","KS","MO","NE"),
84	        '7', Set.of("AR","LA","OK","TX"),
85	        '8', Set.of("AZ","CO","ID","NM","NV","UT","WY"),
86	        '9', Set.of("AK","CA","HI","OR","WA")
87	    );
88	
89	    private void validateAddress(Address address) {
90	        if ("US".equals(address.getCountry())) {
91	            if (address.getState() != null) {
92	                String st = address.getState().toUpperCase();
93	                if (!US_STATES.contains(st)) {
94	                    throw new IllegalArgumentException("Invalid US state code: " + address.getState());
95	                }
96	                address.setState(st);
97	            }
98	            if (address.getPostalCode() != null) {
99	                if (!ZIP_PATTERN.matcher(address.getPostalCode()).matches()) {
100	                    throw new IllegalArgumentException("Invalid US ZIP code format. Expected 12345 or 12345-6789");
101	                }
102	                // Cross-validate ZIP prefix vs state
103	                if (address.getState() != null) {
104	                    char prefix = address.getPostalCode().charAt(0);
105	                    Set<String> validStates = ZIP_STATE_REGIONS.get(prefix);
106	                    if (validStates != null && !validStates.contains(address.getState())) {
107	                        throw new IllegalArgumentException(
108	                                "ZIP code " + address.getPostalCode() + " is not consistent with state " + address.getState());
109	                    }
110	                }
111	            }
112	        }
113	    }
114	}
