74	    @Transactional
75	    public Order createOrder(Long listingId, Long timeSlotId, Long addressId,
76	                             String notes, String deliveryMode, User customer) {
77	        // Validate delivery mode
78	        String mode = (deliveryMode != null) ? deliveryMode.toUpperCase() : "ONSITE";
79	        if (!VALID_DELIVERY_MODES.contains(mode)) {
80	            throw new IllegalArgumentException("Invalid delivery mode. Must be one of: " + VALID_DELIVERY_MODES);
81	        }
82	        if ("COURIER".equals(mode) && addressId == null) {
83	            throw new IllegalArgumentException("Address is required for courier delivery");
84	        }
85	        // Verify address ownership for courier orders
86	        if (addressId != null) {
87	            com.booking.domain.Address addr = addressMapper.findById(addressId);
88	            if (addr == null) {
89	                throw new IllegalArgumentException("Address not found");
90	            }
91	            if (!addr.getUserId().equals(customer.getId())) {
92	                throw new SecurityException("Address does not belong to the current user");
93	            }
94	        }
95	        Listing listing = listingMapper.findById(listingId);
96	        if (listing == null || !listing.getActive()) {
97	            throw new IllegalArgumentException("Listing not found or inactive");
98	        }
99	
100	        // Reserve time slot with row lock — prevents oversell
101	        TimeSlot slot;
102	        try {
103	            slot = timeSlotService.reserveSlot(timeSlotId);
104	        } catch (IllegalStateException e) {
105	            throw new IllegalStateException("Cannot reserve time slot: " + e.getMessage());
106	        }
107	
108	        // Verify slot belongs to listing
109	        if (!slot.getListingId().equals(listingId)) {
110	            // Compensating rollback
111	            timeSlotService.releaseSlot(timeSlotId);
112	            throw new IllegalArgumentException("Time slot does not belong to this listing");
113	        }
114	
115	        Order order = new Order();
116	        order.setOrderNumber("ORD-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase());
117	        order.setCustomerId(customer.getId());
118	        order.setPhotographerId(listing.getPhotographerId());
119	        order.setListingId(listingId);
120	        order.setTimeSlotId(timeSlotId);
121	        order.setStatus(OrderStatus.CREATED.name());
122	        order.setTotalPrice(listing.getPrice());
123	        order.setPaidAmount(BigDecimal.ZERO);
124	        order.setAddressId(addressId);
125	        order.setNotes(notes);
126	        order.setDeliveryMode(mode);
127	        order.setPaymentDeadline(LocalDateTime.now().plusMinutes(PAYMENT_DEADLINE_MINUTES));
128	
129	        try {
130	            orderMapper.insert(order);
131	        } catch (Exception e) {
132	            // Compensating rollback: release the reserved slot
133	            timeSlotService.releaseSlot(timeSlotId);
134	            throw new RuntimeException("Order creation failed, slot released", e);
135	        }
136	
137	        recordAction(order.getId(), "CREATE", null, OrderStatus.CREATED.name(),
138	                customer.getId(), "Order created, payment due in " + PAYMENT_DEADLINE_MINUTES + " min");
139	
140	        notificationService.queueOrderNotification(order, "ORDER_CREATED",
141	                "New order " + order.getOrderNumber() + " created");
142	
143	        return orderMapper.findById(order.getId());
144	    }
