208	    @Transactional
209	    public Order cancel(Long orderId, String reason, User actor) {
210	        Order order = requireOrder(orderId);
211	        enforceAccess(order, actor, "CUSTOMER", "PHOTOGRAPHER", "ADMINISTRATOR");
212	
213	        OrderStatus current = OrderStatus.valueOf(order.getStatus());
214	        if (!current.canTransitionTo(OrderStatus.CANCELLED)) {
215	            throw new IllegalStateException("Cannot cancel from status " + current);
216	        }
217	
218	        transition(order, OrderStatus.CANCELLED, actor.getId(), "Cancelled: " + reason);
219	        order.setCancelReason(reason);
220	        order.setStatus(OrderStatus.CANCELLED.name());
221	        orderMapper.update(order);
222	
223	        // Compensating rollback: release the time slot
224	        timeSlotService.releaseSlot(order.getTimeSlotId());
225	
226	        // If already paid, auto-refund
227	        if (current == OrderStatus.PAID || current == OrderStatus.CHECKED_IN) {
228	            order.setRefundAmount(order.getPaidAmount());
229	            orderMapper.update(order);
230	            recordAction(orderId, "AUTO_REFUND", OrderStatus.CANCELLED.name(),
231	                    OrderStatus.CANCELLED.name(), actor.getId(),
232	                    "Auto-refund of " + order.getPaidAmount());
233	        }
234	
235	        notificationService.queueOrderNotification(order, "ORDER_CANCELLED",
236	                "Order " + order.getOrderNumber() + " has been cancelled");
237	        return orderMapper.findById(orderId);
238	    }
