1	package com.booking.service;
2	
3	import com.booking.domain.Conversation;
4	import com.booking.domain.Message;
5	import com.booking.domain.Order;
6	import com.booking.domain.User;
7	import com.booking.mapper.ConversationMapper;
8	import com.booking.mapper.MessageMapper;
9	import com.booking.mapper.OrderMapper;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.util.List;
14	
15	@Service
16	public class MessageService {
17	
18	    private final ConversationMapper conversationMapper;
19	    private final MessageMapper messageMapper;
20	    private final OrderMapper orderMapper;
21	
22	    public MessageService(ConversationMapper conversationMapper, MessageMapper messageMapper,
23	                          OrderMapper orderMapper) {
24	        this.conversationMapper = conversationMapper;
25	        this.messageMapper = messageMapper;
26	        this.orderMapper = orderMapper;
27	    }
28	
29	    public List<Conversation> getConversations(User user) {
30	        List<Conversation> convos = conversationMapper.findByUserId(user.getId());
31	        for (Conversation c : convos) {
32	            c.setUnreadCount(messageMapper.countUnread(c.getId(), user.getId()));
33	        }
34	        return convos;
35	    }
36	
37	    public List<Message> getMessages(Long conversationId, User user) {
38	        Conversation conv = conversationMapper.findById(conversationId);
39	        if (conv == null) throw new IllegalArgumentException("Conversation not found");
40	        enforceParticipant(conv, user);
41	        // Mark as read
42	        messageMapper.markRead(conversationId, user.getId());
43	        return messageMapper.findByConversationId(conversationId);
44	    }
45	
46	    @Transactional
47	    public Message sendMessage(Long recipientId, String content, Long orderId, User sender) {
48	        if (content == null || content.isBlank()) {
49	            throw new IllegalArgumentException("Message content is required");
50	        }
51	
52	        boolean isAdmin = "ADMINISTRATOR".equals(sender.getRoleName());
53	
54	        // Both CUSTOMER and PHOTOGRAPHER require a valid orderId — no ad-hoc messaging
55	        if (!isAdmin && orderId == null) {
56	            throw new IllegalArgumentException("An order ID is required to start a conversation");
57	        }
58	
59	        // Validate order-scoped authorization when orderId is present
60	        if (orderId != null) {
61	            Order order = orderMapper.findById(orderId);
62	            if (order == null) {
63	                throw new IllegalArgumentException("Order not found");
64	            }
65	            boolean isBuyer = order.getCustomerId().equals(sender.getId());
66	            boolean isSeller = order.getPhotographerId().equals(sender.getId());
67	            if (!isBuyer && !isSeller && !isAdmin) {
68	                throw new SecurityException("Only the buyer or seller of this order can start a conversation");
69	            }
70	            boolean recipientIsBuyer = order.getCustomerId().equals(recipientId);
71	            boolean recipientIsSeller = order.getPhotographerId().equals(recipientId);
72	            if (!recipientIsBuyer && !recipientIsSeller) {
73	                throw new SecurityException("Recipient is not a participant of this order");
74	            }
75	        }
76	
77	        // Find or create conversation
78	        Conversation conv = conversationMapper.findByParticipants(
79	                sender.getId(), recipientId, orderId);
80	
81	        if (conv == null) {
82	            conv = new Conversation();
83	            conv.setParticipantOne(sender.getId());
84	            conv.setParticipantTwo(recipientId);
85	            conv.setOrderId(orderId);
86	            conversationMapper.insert(conv);
87	            conv = conversationMapper.findById(conv.getId());
88	        }
89	
90	        Message msg = new Message();
91	        msg.setConversationId(conv.getId());
92	        msg.setSenderId(sender.getId());
93	        msg.setContent(content);
94	        messageMapper.insert(msg);
95	
96	        conversationMapper.updateLastMessageAt(conv.getId());
97	        return msg;
98	    }
99	
100	    @Transactional
101	    public Message sendToConversation(Long conversationId, String content, User sender) {
102	        Conversation conv = conversationMapper.findById(conversationId);
103	        if (conv == null) throw new IllegalArgumentException("Conversation not found");
104	        enforceParticipant(conv, sender);
105	
106	        if (content == null || content.isBlank()) {
107	            throw new IllegalArgumentException("Message content is required");
108	        }
109	
110	        Message msg = new Message();
111	        msg.setConversationId(conversationId);
112	        msg.setSenderId(sender.getId());
113	        msg.setContent(content);
114	        messageMapper.insert(msg);
115	
116	        conversationMapper.updateLastMessageAt(conversationId);
117	        return msg;
118	    }
119	
120	    private void enforceParticipant(Conversation conv, User user) {
121	        if (!conv.getParticipantOne().equals(user.getId()) &&
122	            !conv.getParticipantTwo().equals(user.getId()) &&
123	            !"ADMINISTRATOR".equals(user.getRoleName())) {
124	            throw new SecurityException("Not a participant in this conversation");
125	        }
126	    }
127	}
