7	import jakarta.servlet.http.HttpSession;
8	import org.springframework.http.ResponseEntity;
9	import org.springframework.web.bind.annotation.*;
10	
11	import java.util.Map;
12	
13	@RestController
14	@RequestMapping("/api/addresses")
15	public class AddressController {
16	
17	    private final AddressService addressService;
18	
19	    public AddressController(AddressService addressService) {
20	        this.addressService = addressService;
21	    }
22	
23	    @GetMapping
24	    public ResponseEntity<?> list(HttpSession session) {
25	        User user = SessionUtil.getCurrentUser(session);
26	        return ResponseEntity.ok(addressService.getByUser(user.getId()));
27	    }
28	
29	    @GetMapping("/{id}")
30	    public ResponseEntity<?> get(@PathVariable Long id, HttpSession session) {
31	        Address addr = addressService.getById(id);
32	        if (addr == null) return ResponseEntity.notFound().build();
33	        User user = SessionUtil.getCurrentUser(session);
34	        if (!addr.getUserId().equals(user.getId()) && !"ADMINISTRATOR".equals(user.getRoleName())) {
35	            return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
36	        }
37	        return ResponseEntity.ok(addr);
38	    }
39	
40	    @PostMapping
41	    public ResponseEntity<?> create(@RequestBody Address address, HttpSession session) {
42	        User user = SessionUtil.getCurrentUser(session);
43	        try {
44	            return ResponseEntity.ok(addressService.create(address, user));
45	        } catch (IllegalArgumentException e) {
46	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
47	        }
48	    }
49	
50	    @PutMapping("/{id}")
51	    public ResponseEntity<?> update(@PathVariable Long id, @RequestBody Address address,
52	                                    HttpSession session) {
53	        User user = SessionUtil.getCurrentUser(session);
54	        try {
55	            address.setId(id);
56	            return ResponseEntity.ok(addressService.update(address, user));
57	        } catch (SecurityException e) {
58	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
59	        } catch (IllegalArgumentException e) {
60	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
61	        }
62	    }
63	
64	    @DeleteMapping("/{id}")
65	    public ResponseEntity<?> delete(@PathVariable Long id, HttpSession session) {
66	        User user = SessionUtil.getCurrentUser(session);
67	        try {
68	            addressService.delete(id, user);
69	            return ResponseEntity.ok(Map.of("message", "Address deleted"));
70	        } catch (SecurityException e) {
71	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
72	        }
73	    }
74	}
