1	package com.booking.service;
2	
3	import com.booking.domain.Listing;
4	import com.booking.domain.User;
5	import com.booking.mapper.ListingMapper;
6	import org.springframework.stereotype.Service;
7	
8	import java.math.BigDecimal;
9	import java.util.LinkedHashMap;
10	import java.util.List;
11	import java.util.Map;
12	
13	@Service
14	public class ListingService {
15	
16	    private static final int DEFAULT_PAGE_SIZE = 20;
17	    private static final int MAX_PAGE_SIZE = 100;
18	
19	    private final ListingMapper listingMapper;
20	
21	    public ListingService(ListingMapper listingMapper) {
22	        this.listingMapper = listingMapper;
23	    }
24	
25	    public Listing getById(Long id) {
26	        return listingMapper.findById(id);
27	    }
28	
29	    public List<Listing> getActive() {
30	        return listingMapper.findActive();
31	    }
32	
33	    public List<Listing> getByPhotographer(Long photographerId) {
34	        return listingMapper.findByPhotographerId(photographerId);
35	    }
36	
37	    private static final java.util.Set<String> VALID_SORTS = java.util.Set.of(
38	            "newest", "price_asc", "price_desc", "rating", "duration");
39	
40	    public Map<String, Object> search(String keyword, String category,
41	                                      BigDecimal minPrice, BigDecimal maxPrice,
42	                                      String location, String locationState, String locationCity,
43	                                      String locationNeighborhood,
44	                                      String theme, String transportMode,
45	                                      BigDecimal minRating, String availableDate,
46	                                      String sortBy, int page, int size) {
47	        int pageSize = Math.min(Math.max(size, 1), MAX_PAGE_SIZE);
48	        int offset = Math.max(page - 1, 0) * pageSize;
49	        String sort = (sortBy != null && VALID_SORTS.contains(sortBy)) ? sortBy : "newest";
50	
51	        List<Listing> items = listingMapper.search(keyword, category, minPrice, maxPrice,
52	                location, locationState, locationCity, locationNeighborhood,
53	                theme, transportMode, minRating, availableDate, sort, offset, pageSize);
54	        long total = listingMapper.searchCount(keyword, category, minPrice, maxPrice,
55	                location, locationState, locationCity, locationNeighborhood,
56	                theme, transportMode, minRating, availableDate);
57	
58	        Map<String, Object> result = new LinkedHashMap<>();
59	        result.put("items", items);
60	        result.put("page", page);
61	        result.put("size", pageSize);
62	        result.put("total", total);
63	        result.put("totalPages", (int) Math.ceil((double) total / pageSize));
64	        return result;
65	    }
66	
67	    public Listing create(Listing listing, User photographer) {
68	        if (!"PHOTOGRAPHER".equals(photographer.getRoleName()) &&
69	            !"ADMINISTRATOR".equals(photographer.getRoleName())) {
70	            throw new SecurityException("Only photographers can create listings");
71	        }
72	        if (listing.getPhotographerId() == null) {
73	            listing.setPhotographerId(photographer.getId());
74	        }
75	        if (!"ADMINISTRATOR".equals(photographer.getRoleName()) &&
76	            !listing.getPhotographerId().equals(photographer.getId())) {
77	            throw new SecurityException("Cannot create listings for other photographers");
78	        }
79	        validateListing(listing);
80	        if (listing.getActive() == null) listing.setActive(true);
81	        if (listing.getMaxConcurrent() == null) listing.setMaxConcurrent(1);
82	        listingMapper.insert(listing);
83	        return listingMapper.findById(listing.getId());
84	    }
85	
86	    public Listing update(Listing listing, User actor) {
87	        Listing existing = listingMapper.findById(listing.getId());
88	        if (existing == null) throw new IllegalArgumentException("Listing not found");
89	        enforceOwnerOrAdmin(existing, actor);
90	        validateListing(listing);
91	        listingMapper.update(listing);
92	        return listingMapper.findById(listing.getId());
93	    }
94	
95	    public boolean isOwner(Long listingId, Long userId) {
96	        Listing listing = listingMapper.findById(listingId);
97	        return listing != null && listing.getPhotographerId().equals(userId);
98	    }
99	
100	    private void enforceOwnerOrAdmin(Listing listing, User actor) {
101	        if (!"ADMINISTRATOR".equals(actor.getRoleName()) &&
102	            !listing.getPhotographerId().equals(actor.getId())) {
103	            throw new SecurityException("Access denied to this listing");
104	        }
105	    }
106	
107	    private void validateListing(Listing listing) {
108	        if (listing.getTitle() == null || listing.getTitle().isBlank())
109	            throw new IllegalArgumentException("Title is required");
110	        if (listing.getPrice() == null || listing.getPrice().signum() <= 0)
111	            throw new IllegalArgumentException("Price must be positive");
112	        if (listing.getDurationMinutes() == null || listing.getDurationMinutes() <= 0)
113	            throw new IllegalArgumentException("Duration must be positive");
114	    }
115	}
