import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.MediaType;
import org.springframework.mock.web.MockHttpSession;
import org.springframework.test.web.servlet.MvcResult;

import com.booking.service.AddressService;
import com.booking.domain.Address;
import com.booking.domain.User;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.concurrent.*;

import static org.hamcrest.Matchers.*;
import static org.junit.jupiter.api.Assertions.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

class StrictAuthAndLifecycleApiIT extends BaseApiIT {

    @Autowired
    private AddressService addressService;

    // ---- Auth Filter: disabled user immediately blocked ----

    @Test void disabledUserSessionRejected() throws Exception {
        MockHttpSession admin = loginAs("admin");
        MockHttpSession cust2 = loginAs("cust2");

        // Verify cust2 can access API
        mvc.perform(get("/api/orders").session(cust2))
            .andExpect(status().isOk());

        // Admin disables cust2 account
        mvc.perform(patch("/api/users/5/enabled").session(admin)
                .contentType(MediaType.APPLICATION_JSON)
                .content(json(Map.of("enabled", false))))
            .andExpect(status().isOk());

        // cust2's active session should now be blocked
        mvc.perform(get("/api/orders").session(cust2))
            .andExpect(status().isForbidden())
            .andExpect(jsonPath("$.error", containsString("disabled")));

        // Re-enable for cleanup
        mvc.perform(patch("/api/users/5/enabled").session(admin)
                .contentType(MediaType.APPLICATION_JSON)
                .content(json(Map.of("enabled", true))))
            .andExpect(status().isOk());
    }

    // ---- Legacy bookings surface returns 410 ----

    @Test void legacyBookingsGone() throws Exception {
        MockHttpSession s = loginAs("cust1");
        mvc.perform(get("/api/bookings").session(s))
            .andExpect(status().isGone())
            .andExpect(jsonPath("$.error", containsString("/api/orders")));
    }

    // ---- Search suggestions are server-side ----

    @Test void searchRecordsTermServerSide() throws Exception {
        MockHttpSession s = loginAs("cust1");
        mvc.perform(get("/api/listings/search?keyword=wedding+photography").session(s))
            .andExpect(status().isOk());

        // Verify suggestions include the recorded term
        mvc.perform(get("/api/listings/search/suggestions").session(s))
            .andExpect(status().isOk())
            .andExpect(jsonPath("$", hasItem("wedding photography")));
    }

    // ---- SSE endpoint responds ----

    @Test void sseStreamEndpoint() throws Exception {
        MockHttpSession s = loginAs("cust1");
        mvc.perform(get("/api/messages/stream").session(s))
            .andExpect(status().isOk());
    }

    // ---- Address default: concurrent set-default contention ----

    @Test void concurrentSetDefaultAddressDoesNotDuplicate() throws Exception {
        // Create multiple addresses for cust1
        User actor = new User();
        actor.setId(4L);
        actor.setRoleName("CUSTOMER");

        // Create two non-default addresses
        Address a1 = new Address();
        a1.setLabel("Contention A");
        a1.setStreet("100 Test St");
        a1.setCity("Springfield");
        a1.setState("IL");
        a1.setPostalCode("62701");
        a1.setCountry("US");
        a1.setIsDefault(false);
        Address created1 = addressService.create(a1, actor);

        Address a2 = new Address();
        a2.setLabel("Contention B");
        a2.setStreet("200 Test St");
        a2.setCity("Springfield");
        a2.setState("IL");
        a2.setPostalCode("62701");
        a2.setCountry("US");
        a2.setIsDefault(false);
        Address created2 = addressService.create(a2, actor);

        // Launch concurrent set-default updates
        ExecutorService executor = Executors.newFixedThreadPool(2);
        CountDownLatch latch = new CountDownLatch(1);
        List<Future<Boolean>> futures = new ArrayList<>();

        for (Long addrId : List.of(created1.getId(), created2.getId())) {
            futures.add(executor.submit(() -> {
                latch.await();
                try {
                    Address upd = new Address();
                    upd.setId(addrId);
                    upd.setLabel("Default Candidate");
                    upd.setStreet("100 Test St");
                    upd.setCity("Springfield");
                    upd.setState("IL");
                    upd.setPostalCode("62701");
                    upd.setCountry("US");
                    upd.setIsDefault(true);
                    addressService.update(upd, actor);
                    return true;
                } catch (Exception e) {
                    return false;
                }
            }));
        }

        latch.countDown(); // Release both threads simultaneously
        executor.shutdown();
        executor.awaitTermination(10, TimeUnit.SECONDS);

        // Verify only one default address exists for the user
        List<Address> addresses = addressService.getByUser(4L);
        long defaultCount = addresses.stream()
                .filter(a -> Boolean.TRUE.equals(a.getIsDefault()))
                .count();
        assertTrue(defaultCount <= 1,
                "Expected at most 1 default address but found " + defaultCount);
    }
}
"}

