1	package com.booking.service;
2	
3	import com.booking.domain.Address;
4	import com.booking.domain.User;
5	import com.booking.mapper.AddressMapper;
6	import org.springframework.stereotype.Service;
7	import org.springframework.transaction.annotation.Transactional;
8	
9	import java.util.List;
10	import java.util.Map;
11	import java.util.Set;
12	import java.util.regex.Pattern;
13	
14	@Service
15	public class AddressService {
16	
17	    private static final Pattern ZIP_PATTERN = Pattern.compile("^\\d{5}(-\\d{4})?$");
18	    private static final Set<String> US_STATES = Set.of(
19	            "AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA",
20	            "KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ",
21	            "NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT",
22	            "VA","WA","WV","WI","WY","DC");
23	
24	    private final AddressMapper addressMapper;
25	
26	    public AddressService(AddressMapper addressMapper) {
27	        this.addressMapper = addressMapper;
28	    }
29	
30	    public List<Address> getByUser(Long userId) {
31	        return addressMapper.findByUserId(userId);
32	    }
33	
34	    public Address getById(Long id) {
35	        return addressMapper.findById(id);
36	    }
37	
38	    @Transactional
39	    public Address create(Address address, User actor) {
40	        address.setUserId(actor.getId());
41	        if (address.getCountry() == null) address.setCountry("US");
42	        validateAddress(address);
43	        if (Boolean.TRUE.equals(address.getIsDefault())) {
44	            // Lock existing defaults via SELECT FOR UPDATE to prevent concurrent duplicates
45	            addressMapper.lockByUserId(actor.getId());
46	            addressMapper.clearDefault(actor.getId());
47	        }
48	        addressMapper.insert(address);
49	        return addressMapper.findById(address.getId());
50	    }
51	
52	    @Transactional
53	    public Address update(Address address, User actor) {
54	        Address existing = addressMapper.findById(address.getId());
55	        if (existing == null) throw new IllegalArgumentException("Address not found");
56	        if (!existing.getUserId().equals(actor.getId()) && !"ADMINISTRATOR".equals(actor.getRoleName())) {
57	            throw new SecurityException("Access denied");
58	        }
59	        address.setUserId(existing.getUserId());
60	        validateAddress(address);
61	        if (Boolean.TRUE.equals(address.getIsDefault())) {
62	            // Lock existing defaults via SELECT FOR UPDATE to prevent concurrent duplicates
63	            addressMapper.lockByUserId(existing.getUserId());
64	            addressMapper.clearDefault(existing.getUserId());
65	        }
66	        addressMapper.update(address);
67	        return addressMapper.findById(address.getId());
68	    }
69	
70	    public void delete(Long id, User actor) {
71	        Address existing = addressMapper.findById(id);
72	        if (existing == null) throw new IllegalArgumentException("Address not found");
73	        if (!existing.getUserId().equals(actor.getId()) && !"ADMINISTRATOR".equals(actor.getRoleName())) {
74	            throw new SecurityException("Access denied");
75	        }
76	        addressMapper.delete(id);
77	    }
78	
79	    // ZIP prefix -> state region mapping for consistency checks
80	    private static final Map<Character, Set<String>> ZIP_STATE_REGIONS = Map.of(
81	        '0', Set.of("CT","MA","ME","NH","NJ","NY","PR","RI","VT","VI","DC"),
82	        '1', Set.of("DE","NY","PA"),
83	        '2', Set.of("DC","MD","NC","SC","VA","WV"),
84	        '3', Set.of("AL","FL","GA","MS","TN"),
85	        '4', Set.of("IN","KY","MI","OH"),
86	        '5', Set.of("IA","MN","MT","ND","NE","SD","WI"),
87	        '6', Set.of("IL","KS","MO","NE"),
88	        '7', Set.of("AR","LA","OK","TX"),
89	        '8', Set.of("AZ","CO","ID","NM","NV","UT","WY"),
90	        '9', Set.of("AK","CA","HI","OR","WA")
91	    );
92	
93	    private void validateAddress(Address address) {
94	        if ("US".equals(address.getCountry())) {
95	            if (address.getState() != null) {
96	                String st = address.getState().toUpperCase();
97	                if (!US_STATES.contains(st)) {
98	                    throw new IllegalArgumentException("Invalid US state code: " + address.getState());
99	                }
100	                address.setState(st);
101	            }
102	            if (address.getPostalCode() != null) {
103	                if (!ZIP_PATTERN.matcher(address.getPostalCode()).matches()) {
104	                    throw new IllegalArgumentException("Invalid US ZIP code format. Expected 12345 or 12345-6789");
105	                }
106	                // Cross-validate ZIP prefix vs state
107	                if (address.getState() != null) {
108	                    char prefix = address.getPostalCode().charAt(0);
109	                    Set<String> validStates = ZIP_STATE_REGIONS.get(prefix);
110	                    if (validStates != null && !validStates.contains(address.getState())) {
111	                        throw new IllegalArgumentException(
112	                                "ZIP code " + address.getPostalCode() + " is not consistent with state " + address.getState());
113	                    }
114	                }
115	            }
116	        }
117	    }
118	}
