1	package com.booking.controller;
2	
3	import com.booking.domain.Attachment;
4	import com.booking.domain.Booking;
5	import com.booking.domain.User;
6	import com.booking.service.AttachmentService;
7	import com.booking.service.BookingService;
8	import com.booking.util.SessionUtil;
9	import jakarta.servlet.http.HttpSession;
10	import org.springframework.core.io.Resource;
11	import org.springframework.core.io.UrlResource;
12	import org.springframework.http.HttpHeaders;
13	import org.springframework.http.MediaType;
14	import org.springframework.http.ResponseEntity;
15	import org.springframework.web.bind.annotation.*;
16	import org.springframework.web.multipart.MultipartFile;
17	
18	import java.net.MalformedURLException;
19	import java.nio.file.Path;
20	import java.util.Map;
21	
22	@RestController
23	@RequestMapping("/api/attachments")
24	public class AttachmentController {
25	
26	    private final AttachmentService attachmentService;
27	    private final BookingService bookingService;
28	
29	    public AttachmentController(AttachmentService attachmentService, BookingService bookingService) {
30	        this.attachmentService = attachmentService;
31	        this.bookingService = bookingService;
32	    }
33	
34	    @GetMapping("/booking/{bookingId}")
35	    public ResponseEntity<?> listForBooking(@PathVariable Long bookingId, HttpSession session) {
36	        User user = SessionUtil.getCurrentUser(session);
37	        Booking booking = bookingService.getById(bookingId);
38	        if (booking == null) return ResponseEntity.notFound().build();
39	        if (!bookingService.canUserAccess(booking, user)) {
40	            return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
41	        }
42	        return ResponseEntity.ok(attachmentService.getByBookingId(bookingId));
43	    }
44	
45	    @PostMapping("/booking/{bookingId}")
46	    public ResponseEntity<?> upload(@PathVariable Long bookingId,
47	                                    @RequestParam("file") MultipartFile file,
48	                                    HttpSession session) {
49	        User user = SessionUtil.getCurrentUser(session);
50	        try {
51	            Attachment attachment = attachmentService.upload(bookingId, file, user);
52	            return ResponseEntity.ok(attachment);
53	        } catch (IllegalArgumentException e) {
54	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
55	        } catch (SecurityException e) {
56	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
57	        }
58	    }
59	
60	    @GetMapping("/{id}/download")
61	    public ResponseEntity<?> download(@PathVariable Long id, HttpSession session) {
62	        User user = SessionUtil.getCurrentUser(session);
63	        Attachment attachment = attachmentService.getById(id);
64	        if (attachment == null) return ResponseEntity.notFound().build();
65	
66	        // IDOR fix: verify caller has access to the parent booking
67	        Booking booking = bookingService.getById(attachment.getBookingId());
68	        if (booking == null || !bookingService.canUserAccess(booking, user)) {
69	            return ResponseEntity.status(403).body(Map.of("error", "Access denied"));
70	        }
71	
72	        Path filePath = attachmentService.getFilePath(attachment);
73	        try {
74	            Resource resource = new UrlResource(filePath.toUri());
75	            if (!resource.exists()) return ResponseEntity.notFound().build();
76	
77	            String contentType = attachment.getContentType() != null
78	                    ? attachment.getContentType() : "application/octet-stream";
79	
80	            return ResponseEntity.ok()
81	                    .contentType(MediaType.parseMediaType(contentType))
82	                    .header(HttpHeaders.CONTENT_DISPOSITION,
83	                            "attachment; filename=\"" + attachment.getOriginalName() + "\"")
84	                    .body(resource);
85	        } catch (MalformedURLException e) {
86	            return ResponseEntity.internalServerError().body(Map.of("error", "File not accessible"));
87	        }
88	    }
89	
90	    @DeleteMapping("/{id}")
91	    public ResponseEntity<?> delete(@PathVariable Long id, HttpSession session) {
92	        User user = SessionUtil.getCurrentUser(session);
93	        try {
94	            attachmentService.delete(id, user);
95	            return ResponseEntity.ok(Map.of("message", "Attachment deleted"));
96	        } catch (IllegalArgumentException e) {
97	            return ResponseEntity.badRequest().body(Map.of("error", e.getMessage()));
98	        } catch (SecurityException e) {
99	            return ResponseEntity.status(403).body(Map.of("error", e.getMessage()));
100	        }
101	    }
102	}
