31	    /**
32	     * Patch-style selective update — only modifies fields present in the map.
33	     * Never overwrites password_hash or encrypted phone.
34	     */
35	    public void patchUpdate(Long id, Map<String, Object> fields) {
36	        User existing = userMapper.findById(id);
37	        if (existing == null) throw new IllegalArgumentException("User not found");
38	
39	        if (fields.containsKey("email")) existing.setEmail((String) fields.get("email"));
40	        if (fields.containsKey("fullName")) existing.setFullName((String) fields.get("fullName"));
41	        if (fields.containsKey("roleId")) existing.setRoleId(((Number) fields.get("roleId")).longValue());
42	        if (fields.containsKey("enabled")) existing.setEnabled((Boolean) fields.get("enabled"));
43	        // phone and passwordHash are never overwritten through this path
44	        userMapper.updateProfile(existing);
45	    }
46	
47	    public void update(User user) {
48	        User existing = userMapper.findById(user.getId());
49	        if (existing == null) throw new IllegalArgumentException("User not found");
