                .contentType(MediaType.APPLICATION_JSON)
                .header("Idempotency-Key", "cov-refund-create")
                .content(json(Map.of("listingId", 3, "timeSlotId", freshSlot))))
            .andExpect(status().isOk()).andReturn();
