1	package com.booking.util;
2	
3	import javax.crypto.Cipher;
4	import javax.crypto.SecretKeyFactory;
5	import javax.crypto.spec.GCMParameterSpec;
6	import javax.crypto.spec.PBEKeySpec;
7	import javax.crypto.spec.SecretKeySpec;
8	import java.nio.charset.StandardCharsets;
9	import java.security.SecureRandom;
10	import java.security.spec.KeySpec;
11	import java.util.Base64;
12	
13	public final class FieldEncryptor {
14	
15	    private static final String ALGORITHM = "AES/GCM/NoPadding";
16	    private static final int GCM_TAG_LENGTH = 128;
17	    private static final int IV_LENGTH = 12;
18	    private static final int AES_KEY_LENGTH = 32; // 256 bits
19	    private static final int PBKDF2_ITERATIONS = 100_000;
20	    private static final byte[] PBKDF2_SALT = "BookingPortalFieldEncryptorSalt!".getBytes(StandardCharsets.UTF_8);
21	    private static final SecureRandom RANDOM = new SecureRandom();
22	
23	    private static volatile SecretKeySpec keySpec;
24	
25	    private FieldEncryptor() {}
26	
27	    public static void configure(String key) {
28	        if (key == null || key.length() < 32) {
29	            throw new IllegalArgumentException("Encryption key must be at least 32 characters for AES-256");
30	        }
31	        try {
32	            // Derive a proper 32-byte (256-bit) key via PBKDF2
33	            KeySpec spec = new PBEKeySpec(key.toCharArray(), PBKDF2_SALT, PBKDF2_ITERATIONS, AES_KEY_LENGTH * 8);
34	            SecretKeyFactory factory = SecretKeyFactory.getInstance("PBKDF2WithHmacSHA256");
35	            byte[] derived = factory.generateSecret(spec).getEncoded();
36	            keySpec = new SecretKeySpec(derived, "AES");
37	        } catch (Exception e) {
38	            throw new RuntimeException("Failed to derive encryption key via PBKDF2", e);
39	        }
40	    }
41	
42	    private static SecretKeySpec getKeySpec() {
43	        if (keySpec == null) {
44	            throw new IllegalStateException(
45	                "Encryption key not configured. Set ENCRYPTION_KEY environment variable or app.encryption-key property.");
46	        }
47	        return keySpec;
48	    }
49	
50	    public static boolean isConfigured() {
51	        return keySpec != null;
52	    }
53	
54	    public static String encrypt(String plaintext) {
55	        if (plaintext == null) return null;
56	        try {
57	            byte[] iv = new byte[IV_LENGTH];
58	            RANDOM.nextBytes(iv);
59	            Cipher cipher = Cipher.getInstance(ALGORITHM);
60	            cipher.init(Cipher.ENCRYPT_MODE, getKeySpec(), new GCMParameterSpec(GCM_TAG_LENGTH, iv));
61	            byte[] encrypted = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
62	            byte[] combined = new byte[IV_LENGTH + encrypted.length];
63	            System.arraycopy(iv, 0, combined, 0, IV_LENGTH);
64	            System.arraycopy(encrypted, 0, combined, IV_LENGTH, encrypted.length);
65	            return Base64.getEncoder().encodeToString(combined);
66	        } catch (Exception e) {
67	            throw new RuntimeException("Encryption failed", e);
68	        }
69	    }
70	
71	    public static String decrypt(String ciphertext) {
72	        if (ciphertext == null) return null;
73	        try {
74	            byte[] combined = Base64.getDecoder().decode(ciphertext);
75	            byte[] iv = new byte[IV_LENGTH];
76	            System.arraycopy(combined, 0, iv, 0, IV_LENGTH);
77	            byte[] encrypted = new byte[combined.length - IV_LENGTH];
78	            System.arraycopy(combined, IV_LENGTH, encrypted, 0, encrypted.length);
79	            Cipher cipher = Cipher.getInstance(ALGORITHM);
80	            cipher.init(Cipher.DECRYPT_MODE, getKeySpec(), new GCMParameterSpec(GCM_TAG_LENGTH, iv));
81	            return new String(cipher.doFinal(encrypted), StandardCharsets.UTF_8);
82	        } catch (Exception e) {
83	            throw new RuntimeException("Decryption failed", e);
84	        }
85	    }
86	}
