1	package com.booking.service;
2	
3	import com.booking.domain.Booking;
4	import com.booking.domain.BookingStatus;
5	import com.booking.domain.User;
6	import com.booking.mapper.BookingMapper;
7	import com.booking.mapper.ServiceMapper;
8	import org.springframework.stereotype.Service;
9	
10	import java.time.LocalDate;
11	import java.util.List;
12	
13	@Service
14	public class BookingService {
15	
16	    private final BookingMapper bookingMapper;
17	    private final ServiceMapper serviceMapper;
18	
19	    public BookingService(BookingMapper bookingMapper, ServiceMapper serviceMapper) {
20	        this.bookingMapper = bookingMapper;
21	        this.serviceMapper = serviceMapper;
22	    }
23	
24	    public Booking getById(Long id) {
25	        return bookingMapper.findById(id);
26	    }
27	
28	    public List<Booking> getAll() {
29	        return bookingMapper.findAll();
30	    }
31	
32	    public List<Booking> getForUser(User user) {
33	        return switch (user.getRoleName()) {
34	            case "CUSTOMER" -> bookingMapper.findByCustomerId(user.getId());
35	            case "PHOTOGRAPHER" -> bookingMapper.findByPhotographerId(user.getId());
36	            default -> bookingMapper.findAll();
37	        };
38	    }
39	
40	    public Booking create(Booking booking) {
41	        validateBookingDates(booking);
42	        checkPhotographerConflicts(booking);
43	
44	        com.booking.domain.Service svc = serviceMapper.findById(booking.getServiceId());
45	        if (svc == null || !svc.getActive()) {
46	            throw new IllegalArgumentException("Invalid or inactive service");
47	        }
48	
49	        booking.setStatus(BookingStatus.PENDING.name());
50	        if (booking.getTotalPrice() == null) {
51	            booking.setTotalPrice(svc.getPrice());
52	        }
53	
54	        bookingMapper.insert(booking);
55	        return bookingMapper.findById(booking.getId());
56	    }
57	
58	    public Booking update(Booking booking, User actor) {
59	        Booking existing = bookingMapper.findById(booking.getId());
60	        if (existing == null) {
61	            throw new IllegalArgumentException("Booking not found");
62	        }
63	
64	        enforceOwnershipOrAdmin(existing, actor);
65	        validateBookingDates(booking);
66	        checkPhotographerConflicts(booking);
67	
68	        bookingMapper.update(booking);
69	        return bookingMapper.findById(booking.getId());
70	    }
71	
72	    public void updateStatus(Long bookingId, String newStatus, User actor) {
73	        Booking existing = bookingMapper.findById(bookingId);
74	        if (existing == null) {
75	            throw new IllegalArgumentException("Booking not found");
76	        }
77	
78	        enforceOwnershipOrAdmin(existing, actor);
79	
80	        BookingStatus currentStatus = BookingStatus.valueOf(existing.getStatus());
81	        BookingStatus targetStatus = BookingStatus.valueOf(newStatus);
82	
83	        if (!currentStatus.canTransitionTo(targetStatus)) {
84	            throw new IllegalStateException(
85	                    "Cannot transition from " + currentStatus + " to " + targetStatus);
86	        }
87	
88	        bookingMapper.updateStatus(bookingId, newStatus);
89	    }
90	
91	    public boolean canUserAccess(Booking booking, User user) {
92	        if ("ADMINISTRATOR".equals(user.getRoleName())) return true;
93	        if ("CUSTOMER".equals(user.getRoleName()) && booking.getCustomerId().equals(user.getId())) return true;
94	        if ("PHOTOGRAPHER".equals(user.getRoleName()) && user.getId().equals(booking.getPhotographerId())) return true;
95	        return false;
96	    }
97	
98	    private void enforceOwnershipOrAdmin(Booking booking, User actor) {
99	        if (!canUserAccess(booking, actor)) {
100	            throw new SecurityException("Access denied to this booking");
101	        }
102	    }
103	
104	    private void validateBookingDates(Booking booking) {
105	        if (booking.getBookingDate() == null) {
106	            throw new IllegalArgumentException("Booking date is required");
107	        }
108	        if (booking.getStartTime() == null || booking.getEndTime() == null) {
109	            throw new IllegalArgumentException("Start and end times are required");
110	        }
111	        if (!booking.getEndTime().isAfter(booking.getStartTime())) {
112	            throw new IllegalArgumentException("End time must be after start time");
113	        }
114	        if (booking.getBookingDate().isBefore(LocalDate.now())) {
115	            throw new IllegalArgumentException("Booking date cannot be in the past");
116	        }
117	    }
118	
119	    private void checkPhotographerConflicts(Booking booking) {
120	        if (booking.getPhotographerId() == null) return;
121	
122	        List<Booking> conflicts = bookingMapper.findConflicting(
123	                booking.getPhotographerId(),
124	                booking.getBookingDate(),
125	                booking.getStartTime().toString(),
126	                booking.getEndTime().toString(),
127	                booking.getId()
128	        );
129	
130	        if (!conflicts.isEmpty()) {
131	            throw new IllegalStateException("Photographer has a conflicting booking at this time");
132	        }
133	    }
134	}
