1	package com.booking.service;
2	
3	import com.booking.domain.Attachment;
4	import com.booking.domain.Booking;
5	import com.booking.domain.User;
6	import com.booking.mapper.AttachmentMapper;
7	import org.springframework.beans.factory.annotation.Value;
8	import org.springframework.stereotype.Service;
9	import org.springframework.web.multipart.MultipartFile;
10	
11	import java.io.IOException;
12	import java.nio.file.Files;
13	import java.nio.file.Path;
14	import java.nio.file.Paths;
15	import java.util.List;
16	import java.util.UUID;
17	
18	@Service
19	public class AttachmentService {
20	
21	    private final AttachmentMapper attachmentMapper;
22	    private final BookingService bookingService;
23	    private final Path uploadDir;
24	
25	    public AttachmentService(AttachmentMapper attachmentMapper,
26	                             BookingService bookingService,
27	                             @Value("${app.upload-dir}") String uploadDir) {
28	        this.attachmentMapper = attachmentMapper;
29	        this.bookingService = bookingService;
30	        this.uploadDir = Paths.get(uploadDir);
31	        try {
32	            Files.createDirectories(this.uploadDir);
33	        } catch (IOException e) {
34	            throw new RuntimeException("Could not create upload directory", e);
35	        }
36	    }
37	
38	    public List<Attachment> getByBookingId(Long bookingId) {
39	        return attachmentMapper.findByBookingId(bookingId);
40	    }
41	
42	    public Attachment getById(Long id) {
43	        return attachmentMapper.findById(id);
44	    }
45	
46	    public Path getFilePath(Attachment attachment) {
47	        return uploadDir.resolve(attachment.getFileName());
48	    }
49	
50	    public Attachment upload(Long bookingId, MultipartFile file, User uploader) {
51	        Booking booking = bookingService.getById(bookingId);
52	        if (booking == null) {
53	            throw new IllegalArgumentException("Booking not found");
54	        }
55	        if (!bookingService.canUserAccess(booking, uploader)) {
56	            throw new SecurityException("Access denied to this booking");
57	        }
58	
59	        String originalName = file.getOriginalFilename();
60	        String storedName = UUID.randomUUID() + "_" + sanitizeFileName(originalName);
61	
62	        try {
63	            Path target = uploadDir.resolve(storedName);
64	            Files.copy(file.getInputStream(), target);
65	        } catch (IOException e) {
66	            throw new RuntimeException("Failed to store file", e);
67	        }
68	
69	        Attachment attachment = new Attachment();
70	        attachment.setBookingId(bookingId);
71	        attachment.setFileName(storedName);
72	        attachment.setOriginalName(originalName);
73	        attachment.setContentType(file.getContentType());
74	        attachment.setFileSize(file.getSize());
75	        attachment.setUploadedBy(uploader.getId());
76	        attachmentMapper.insert(attachment);
77	
78	        return attachmentMapper.findById(attachment.getId());
79	    }
80	
81	    public void delete(Long attachmentId, User actor) {
82	        Attachment attachment = attachmentMapper.findById(attachmentId);
83	        if (attachment == null) {
84	            throw new IllegalArgumentException("Attachment not found");
85	        }
86	
87	        Booking booking = bookingService.getById(attachment.getBookingId());
88	        if (!bookingService.canUserAccess(booking, actor)) {
89	            throw new SecurityException("Access denied");
90	        }
91	
92	        try {
93	            Files.deleteIfExists(uploadDir.resolve(attachment.getFileName()));
94	        } catch (IOException e) {
95	            // Log but don't fail — DB record removal is more important
96	        }
97	        attachmentMapper.delete(attachmentId);
98	    }
99	
100	    private String sanitizeFileName(String name) {
101	        if (name == null) return "file";
102	        return name.replaceAll("[^a-zA-Z0-9._-]", "_");
103	    }
104	}
