3	public enum BookingStatus {
4	    PENDING,
5	    CONFIRMED,
6	    IN_PROGRESS,
7	    COMPLETED,
8	    CANCELLED;
9	
10	    public boolean canTransitionTo(BookingStatus target) {
11	        return switch (this) {
12	            case PENDING -> target == CONFIRMED || target == CANCELLED;
13	            case CONFIRMED -> target == IN_PROGRESS || target == CANCELLED;
14	            case IN_PROGRESS -> target == COMPLETED || target == CANCELLED;
15	            case COMPLETED, CANCELLED -> false;
16	        };
17	    }
18	}
